/*!
 * Clair Dunne Website - Complete JavaScript
 * Organized by: Core Functions → Desktop Features → Mobile Features → Utils
 */

(function() {
    'use strict';

    // ================================================================
    // CONFIGURATION & CONSTANTS
    // ================================================================
    const CONFIG = {
        ANIMATION_DURATION: 300,
        SCROLL_THRESHOLD: 100,
        MOBILE_BREAKPOINT: 768,
        TABLET_BREAKPOINT: 991,
        DESKTOP_BREAKPOINT: 1200
    };

    // ================================================================
    // CACHED DOM ELEMENTS
    // ================================================================
    const elements = {
        loader: null,
        burgerMenu: null,
        mobileDropdown: null,
        navOverlay: null,
        navLinks: null,
        backToTop: null,
        modal: null,
        modalClose: null,
        modalContent: null,
        videoBtn: null,
        logoOverlay: null
    };

    // ================================================================
    // UTILITY FUNCTIONS
    // ================================================================
    const utils = {
        // Device detection
        isMobile: () => window.innerWidth <= CONFIG.MOBILE_BREAKPOINT,
        isTablet: () => window.innerWidth > CONFIG.MOBILE_BREAKPOINT && window.innerWidth <= CONFIG.TABLET_BREAKPOINT,
        isDesktop: () => window.innerWidth > CONFIG.TABLET_BREAKPOINT,
        
        // Performance utilities
        debounce: function(func, wait) {
            let timeout;
            return function executedFunction(...args) {
                const later = () => {
                    clearTimeout(timeout);
                    func(...args);
                };
                clearTimeout(timeout);
                timeout = setTimeout(later, wait);
            };
        },

        throttle: function(func, limit) {
            let inThrottle;
            return function() {
                const args = arguments;
                const context = this;
                if (!inThrottle) {
                    func.apply(context, args);
                    inThrottle = true;
                    setTimeout(() => inThrottle = false, limit);
                }
            };
        },

        // Get scroll position
        getScrollPosition: () => window.pageYOffset || document.documentElement.scrollTop,
        
        // Console logging with device info
        log: function(message, type = 'info') {
            const deviceType = this.isMobile() ? 'Mobile' : this.isTablet() ? 'Tablet' : 'Desktop';
            console[type](`[${deviceType}] ${message}`);
        }
    };

    // ================================================================
    // DOM ELEMENT INITIALIZATION
    // ================================================================
    function initElements() {
        elements.loader = document.querySelector('.probootstrap-loader');
        elements.burgerMenu = document.querySelector('.probootstrap-burger-menu');
        elements.mobileDropdown = document.querySelector('.mobile-nav-dropdown');
        elements.navOverlay = document.querySelector('.probootstrap-nav-overlay');
        elements.navLinks = document.querySelectorAll('.probootstrap-main-nav a, .mobile-nav-list a');
        elements.backToTop = document.querySelector('.js-gotop');
        elements.modal = document.getElementById('myModal');
        elements.modalClose = document.querySelector('.modal-close');
        elements.modalContent = document.querySelector('.modal-content');
        elements.videoBtn = document.getElementById('myBtn');
        elements.logoOverlay = document.querySelector('.probootstrap-logo-overlay');
        
        utils.log('DOM elements initialized');
    }

    // ================================================================
    // LOADING ANIMATION (ALL DEVICES)
    // ================================================================
    const loader = {
        hide: function() {
            if (elements.loader) {
                setTimeout(() => {
                    elements.loader.style.opacity = '0';
                    setTimeout(() => {
                        elements.loader.style.display = 'none';
                        utils.log('Loader hidden');
                    }, 300);
                }, 100);
            }
        }
    };

    // ================================================================
    // MOBILE NAVIGATION (PHONES ONLY - ≤768px)
    // ================================================================
    const mobileMenu = {
        isOpen: false,

        init: function() {
            utils.log('Initializing mobile menu for all devices');
            
            // Create mobile dropdown if it doesn't exist
            this.createMobileDropdown();
            
            if (elements.burgerMenu && elements.mobileDropdown) {
                // Remove any existing listeners
                elements.burgerMenu.removeEventListener('click', this.toggle);
                
                // Add click listener
                elements.burgerMenu.addEventListener('click', this.toggle.bind(this));
                
                // Close menu when clicking nav links
                const mobileNavLinks = elements.mobileDropdown.querySelectorAll('a');
                mobileNavLinks.forEach(link => {
                    link.addEventListener('click', () => {
                        this.close();
                    });
                });

                // Close menu when clicking outside
                document.addEventListener('click', (e) => {
                    if (this.isOpen && 
                        !elements.mobileDropdown.contains(e.target) && 
                        !elements.burgerMenu.contains(e.target)) {
                        this.close();
                    }
                });
                
                // Close menu on escape key
                document.addEventListener('keydown', (e) => {
                    if (e.key === 'Escape' && this.isOpen) {
                        this.close();
                    }
                });
                
                // Close menu when scrolling on mobile
                if (utils.isMobile()) {
                    window.addEventListener('scroll', utils.throttle(() => {
                        if (this.isOpen) {
                            this.close();
                        }
                    }, 100));
                }
                
                utils.log('Mobile menu event listeners attached');
            }
        },
        
        createMobileDropdown: function() {
            // Remove existing dropdown if it exists
            const existingDropdown = document.querySelector('.mobile-nav-dropdown');
            if (existingDropdown) {
                existingDropdown.remove();
            }
            
            // Create mobile dropdown element
            const dropdown = document.createElement('div');
            dropdown.className = 'mobile-nav-dropdown';
            
            // Get navigation items from main nav
            const mainNav = elements.navOverlay ? elements.navOverlay.querySelector('.probootstrap-main-nav') : null;
            if (mainNav) {
                const mobileList = document.createElement('ul');
                mobileList.className = 'mobile-nav-list';
                
                // Clone navigation items
                const navItems = mainNav.querySelectorAll('li');
                navItems.forEach(item => {
                    const clonedItem = item.cloneNode(true);
                    mobileList.appendChild(clonedItem);
                });
                
                dropdown.appendChild(mobileList);
                document.body.appendChild(dropdown);
                elements.mobileDropdown = dropdown;
                
                utils.log('Mobile dropdown created and added to DOM');
            }
        },

        toggle: function(e) {
            e.preventDefault();
            e.stopPropagation();
            
            utils.log(`Mobile menu toggle clicked - currently ${this.isOpen ? 'open' : 'closed'}`);
            this.isOpen ? this.close() : this.open();
        },

        open: function() {
            if (elements.mobileDropdown && elements.burgerMenu) {
                elements.mobileDropdown.classList.add('show');
                elements.burgerMenu.classList.add('active');
                this.isOpen = true;
                utils.log('Mobile menu opened');
            }
        },

        close: function() {
            if (elements.mobileDropdown && elements.burgerMenu) {
                elements.mobileDropdown.classList.remove('show');
                elements.burgerMenu.classList.remove('active');
                this.isOpen = false;
                utils.log('Mobile menu closed');
            }
        }
    };

    // ================================================================
    // ENHANCED VIDEO MODAL (ALL DEVICES)
    // ================================================================
    const videoModal = {
        videoUrl: "https://www.youtube.com/embed/EDkTA3oewCs?autoplay=1&rel=0&modestbranding=1",
        
        init: function() {
            if (elements.videoBtn && elements.modal) {
                elements.videoBtn.addEventListener('click', this.open.bind(this));
                
                if (elements.modalClose) {
                    elements.modalClose.addEventListener('click', this.close.bind(this));
                }

                // Close on escape key
                document.addEventListener('keydown', (e) => {
                    if (e.key === 'Escape' && elements.modal && elements.modal.classList.contains('show')) {
                        this.close();
                    }
                });

                // Close when clicking outside modal content
                if (elements.modal) {
                    elements.modal.addEventListener('click', (e) => {
                        if (e.target === elements.modal) {
                            this.close();
                        }
                    });
                }
                
                // Mobile touch gestures
                if (utils.isMobile()) {
                    this.initMobileGestures();
                }
                
                utils.log('Video modal initialized');
            }
        },
        
        initMobileGestures: function() {
            let startY = 0;
            let currentY = 0;
            let isDragging = false;
            
            elements.modal.addEventListener('touchstart', (e) => {
                if (e.target === elements.modal) {
                    startY = e.touches[0].clientY;
                    isDragging = true;
                }
            });
            
            elements.modal.addEventListener('touchmove', (e) => {
                if (!isDragging || e.target !== elements.modal) return;
                
                currentY = e.touches[0].clientY;
                const deltaY = currentY - startY;
                
                // Allow closing by swiping down
                if (deltaY > 50 && elements.modalContent) {
                    elements.modalContent.style.transform = `translateY(${deltaY - 50}px) scale(${Math.max(0.8, 1 - deltaY / 500)})`;
                }
            });
            
            elements.modal.addEventListener('touchend', () => {
                if (!isDragging) return;
                
                const deltaY = currentY - startY;
                
                if (deltaY > 100) {
                    this.close();
                } else if (elements.modalContent) {
                    elements.modalContent.style.transform = 'translateY(0) scale(1)';
                }
                
                isDragging = false;
            });
        },

        open: function(e) {
            if (e) e.preventDefault();
            
            if (!elements.modal || !elements.modalContent) return;
            
            // Show loading state
            elements.modalContent.innerHTML = `
                <div class="modal-loading">
                    <div class="loading-spinner"></div>
                    Loading video...
                </div>
            `;
            
            // Show modal with fade in
            elements.modal.style.display = 'flex';
            
            // Smooth transition
            setTimeout(() => {
                elements.modal.classList.add('show');
            }, 10);
            
            // Load video after a short delay
            setTimeout(() => {
                elements.modalContent.innerHTML = `
                    <iframe 
                        src="${this.videoUrl}" 
                        width="100%" 
                        height="100%"
                        frameborder="0" 
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                        allowfullscreen>
                    </iframe>
                `;
            }, 300);
            
            // Prevent body scroll and zoom on mobile
            this.lockBody();
            
            utils.log('Video modal opened');
        },

        close: function(e) {
            if (e) e.preventDefault();
            
            if (!elements.modal) return;
            
            // Fade out
            elements.modal.classList.remove('show');
            
            // Hide modal and clean up after animation
            setTimeout(() => {
                elements.modal.style.display = 'none';
                // Remove video to stop playback
                if (elements.modalContent) {
                    elements.modalContent.innerHTML = '';
                }
                // Restore body scroll
                this.unlockBody();
            }, 300);
            
            utils.log('Video modal closed');
        },
        
        lockBody: function() {
            if (utils.isMobile()) {
                // Prevent zoom on mobile
                const viewport = document.querySelector('meta[name=viewport]');
                if (viewport) {
                    viewport.setAttribute('content', 'width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no');
                }
                
                // Lock body scroll
                document.body.style.position = 'fixed';
                document.body.style.top = `-${utils.getScrollPosition()}px`;
                document.body.style.width = '100%';
            } else {
                document.body.style.overflow = 'hidden';
            }
        },
        
        unlockBody: function() {
            if (utils.isMobile()) {
                // Restore zoom capability
                const viewport = document.querySelector('meta[name=viewport]');
                if (viewport) {
                    viewport.setAttribute('content', 'width=device-width, initial-scale=1');
                }
                
                // Restore scroll position
                const scrollY = document.body.style.top;
                document.body.style.position = '';
                document.body.style.top = '';
                document.body.style.width = '';
                window.scrollTo(0, parseInt(scrollY || '0') * -1);
            } else {
                document.body.style.overflow = '';
            }
        }
    };

    // ================================================================
    // BACK TO TOP FUNCTIONALITY (ALL DEVICES)
    // ================================================================
    const backToTop = {
        init: function() {
            if (elements.backToTop) {
                elements.backToTop.addEventListener('click', this.scrollToTop);
                window.addEventListener('scroll', utils.throttle(this.toggleVisibility.bind(this), 100));
                utils.log('Back to top initialized');
            }
        },

        toggleVisibility: function() {
            if (utils.getScrollPosition() > CONFIG.SCROLL_THRESHOLD) {
                if (elements.backToTop) {
                    elements.backToTop.style.opacity = '1';
                    elements.backToTop.style.visibility = 'visible';
                }
            } else {
                if (elements.backToTop) {
                    elements.backToTop.style.opacity = '0';
                    elements.backToTop.style.visibility = 'hidden';
                }
            }
        },

        scrollToTop: function(e) {
            e.preventDefault();
            window.scrollTo({
                top: 0,
                behavior: 'smooth'
            });
            utils.log('Scrolled to top');
        }
    };

    // ================================================================
    // MOBILE NAVIGATION AUTO-HIDE (MOBILE ONLY)
    // ================================================================
    const mobileNavAutoHide = {
        lastScrollTop: 0,
        scrollTimer: null,
        
        init: function() {
            if (!utils.isMobile() || !elements.navOverlay) return;
            
            window.addEventListener('scroll', utils.throttle(this.handleScroll.bind(this), 50));
            utils.log('Mobile nav auto-hide initialized');
        },
        
        handleScroll: function() {
            const scrollTop = utils.getScrollPosition();
            
            // Clear existing timer
            if (this.scrollTimer) {
                clearTimeout(this.scrollTimer);
            }
            
            // Close mobile menu when scrolling
            if (mobileMenu.isOpen) {
                mobileMenu.close();
            }
            
            // Hide nav when scrolling down, show when scrolling up
            if (scrollTop > this.lastScrollTop && scrollTop > 100) {
                elements.navOverlay.style.transform = 'translateY(-100px)';
                elements.navOverlay.style.opacity = '0.3';
            } else {
                elements.navOverlay.style.transform = 'translateY(0)';
                elements.navOverlay.style.opacity = '1';
            }
            
            // Always show nav when scrolling stops
            this.scrollTimer = setTimeout(() => {
                elements.navOverlay.style.transform = 'translateY(0)';
                elements.navOverlay.style.opacity = '1';
            }, 150);
            
            this.lastScrollTop = scrollTop;
        }
    };

    // ================================================================
    // MOBILE TOUCH ENHANCEMENTS (MOBILE ONLY)
    // ================================================================
    const mobileTouch = {
        init: function() {
            if (!utils.isMobile()) return;
            
            this.addTouchFeedback();
            this.addHapticFeedback();
            utils.log('Mobile touch enhancements initialized');
        },
        
        addTouchFeedback: function() {
            const touchElements = document.querySelectorAll('.btn, a, .probootstrap-burger-menu, .mobile-nav-list a');
            touchElements.forEach(element => {
                element.addEventListener('touchstart', function() {
                    this.style.transform = 'scale(0.98)';
                    this.style.transition = 'transform 0.1s ease';
                });
                
                element.addEventListener('touchend', function() {
                    this.style.transform = 'scale(1)';
                });
                
                element.addEventListener('touchcancel', function() {
                    this.style.transform = 'scale(1)';
                });
            });
        },
        
        addHapticFeedback: function() {
            if ('vibrate' in navigator) {
                const hapticElements = document.querySelectorAll('.btn, .probootstrap-burger-menu, .mobile-nav-list a');
                hapticElements.forEach(element => {
                    element.addEventListener('touchstart', function() {
                        navigator.vibrate(10); // Subtle haptic feedback
                    });
                });
            }
        }
    };

    // ================================================================
    // SMOOTH SCROLL FOR ANCHOR LINKS (ALL DEVICES)
    // ================================================================
    const smoothScroll = {
        init: function() {
            const anchorLinks = document.querySelectorAll('a[href^="#"]');
            anchorLinks.forEach(link => {
                link.addEventListener('click', this.handleClick);
            });
            utils.log('Smooth scroll initialized');
        },

        handleClick: function(e) {
            const href = e.target.getAttribute('href');
            if (href && href !== '#') {
                const target = document.querySelector(href);
                if (target) {
                    e.preventDefault();
                    
                    // Close mobile menu if open
                    if (utils.isMobile() && mobileMenu.isOpen) {
                        mobileMenu.close();
                        setTimeout(() => {
                            target.scrollIntoView({
                                behavior: 'smooth',
                                block: 'start'
                            });
                        }, 300);
                    } else {
                        target.scrollIntoView({
                            behavior: 'smooth',
                            block: 'start'
                        });
                    }
                }
            }
        }
    };

    // ================================================================
    // SCROLL ANIMATIONS (ALL DEVICES)
    // ================================================================
    const scrollAnimations = {
        init: function() {
            const animateElements = document.querySelectorAll('.animate, .section-half .inner');
            
            if ('IntersectionObserver' in window) {
                this.setupIntersectionObserver(animateElements);
            } else {
                // Fallback for older browsers
                window.addEventListener('scroll', utils.throttle(() => {
                    this.checkElements(animateElements);
                }, 100));
                this.checkElements(animateElements);
            }
            
            utils.log('Scroll animations initialized');
        },

        setupIntersectionObserver: function(elements) {
            const observer = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        entry.target.style.opacity = '1';
                        entry.target.style.transform = 'translateY(0)';
                        
                        // Add stagger effect for mobile
                        if (utils.isMobile()) {
                            entry.target.classList.add('visible');
                        }
                        
                        observer.unobserve(entry.target);
                    }
                });
            }, {
                threshold: 0.1,
                rootMargin: utils.isMobile() ? '0px 0px -10% 0px' : '0px 0px -50px 0px'
            });

            elements.forEach(element => {
                element.style.opacity = '0';
                element.style.transform = utils.isMobile() ? 'translateY(20px)' : 'translateY(30px)';
                element.style.transition = 'all 0.6s ease';
                observer.observe(element);
            });
        },

        checkElements: function(elements) {
            elements.forEach(element => {
                const rect = element.getBoundingClientRect();
                const isVisible = rect.top < window.innerHeight && rect.bottom > 0;
                
                if (isVisible) {
                    element.style.opacity = '1';
                    element.style.transform = 'translateY(0)';
                }
            });
        }
    };

    // ================================================================
    // WINDOW RESIZE HANDLER (ALL DEVICES)
    // ================================================================
    const resizeHandler = {
        init: function() {
            window.addEventListener('resize', utils.debounce(this.handleResize.bind(this), 250));
            window.addEventListener('orientationchange', utils.debounce(this.handleOrientationChange.bind(this), 500));
            utils.log('Resize handler initialized');
        },
        
        handleResize: function() {
            const deviceType = utils.isMobile() ? 'Mobile' : utils.isTablet() ? 'Tablet' : 'Desktop';
            utils.log(`Window resized - Device: ${deviceType} (${window.innerWidth}x${window.innerHeight})`);
            
            // Close mobile menu when switching to desktop/tablet
            if (!utils.isMobile() && mobileMenu.isOpen) {
                mobileMenu.close();
            }
            
            // Reinitialize mobile features if switching to mobile
            if (utils.isMobile()) {
                mobileMenu.init();
                mobileNavAutoHide.init();
                mobileTouch.init();
            }
            
            // Recalculate modal sizing if open
            if (elements.modal && elements.modal.classList.contains('show')) {
                setTimeout(() => {
                    elements.modal.style.display = 'none';
                    elements.modal.offsetHeight; // Trigger reflow
                    elements.modal.style.display = 'flex';
                }, 100);
            }
        },
        
        handleOrientationChange: function() {
            utils.log('Orientation changed');
            
            setTimeout(() => {
                // Close mobile menu on orientation change
                if (mobileMenu.isOpen) {
                    mobileMenu.close();
                }
                
                // Recalculate modal sizing
                if (elements.modal && elements.modal.classList.contains('show')) {
                    setTimeout(() => {
                        elements.modal.style.display = 'none';
                        elements.modal.offsetHeight; // Trigger reflow
                        elements.modal.style.display = 'flex';
                    }, 100);
                }
            }, 500);
        }
    };

    // ================================================================
    // PAGE VISIBILITY HANDLER (ALL DEVICES)
    // ================================================================
    const visibilityHandler = {
        init: function() {
            document.addEventListener('visibilitychange', this.handleVisibilityChange.bind(this));
            utils.log('Visibility handler initialized');
        },
        
        handleVisibilityChange: function() {
            if (document.hidden) {
                // Close modal when page becomes hidden
                if (elements.modal && elements.modal.classList.contains('show')) {
                    videoModal.close();
                }
                
                // Close mobile menu when page becomes hidden
                if (mobileMenu.isOpen) {
                    mobileMenu.close();
                }
                
                utils.log('Page hidden - closed open elements');
            }
        }
    };

    // ================================================================
    // PERFORMANCE MONITORING (DEVELOPMENT)
    // ================================================================
    const performance = {
        init: function() {
            // Monitor page load performance
            window.addEventListener('load', () => {
                if ('performance' in window && performance.timing) {
                    const loadTime = performance.timing.loadEventEnd - performance.timing.navigationStart;
                    utils.log(`Page load time: ${loadTime}ms`);
                }
            });
        }
    };

    // ================================================================
    // ERROR HANDLING (ALL DEVICES)
    // ================================================================
    const errorHandler = {
        init: function() {
            window.addEventListener('error', this.handleError);
            window.addEventListener('unhandledrejection', this.handlePromiseRejection);
            utils.log('Error handler initialized');
        },

        handleError: function(error) {
            utils.log(`JavaScript Error: ${error.message}`, 'error');
        },

        handlePromiseRejection: function(event) {
            utils.log(`Unhandled Promise Rejection: ${event.reason}`, 'error');
        }
    };

    // ================================================================
    // LEGACY MODAL SUPPORT (BACKWARDS COMPATIBILITY)
    // ================================================================
    const legacyModal = {
        init: function() {
            // Support for old modal structure
            const modal = document.getElementById("myModal");
            const btn = document.getElementById("myBtn");
            const span = document.getElementsByClassName("close")[0];

            if (btn && modal) {
                btn.onclick = function() {
                    videoModal.open();
                }
            }

            if (span && modal) {
                span.onclick = function() {
                    videoModal.close();
                }
            }

            window.onclick = function(event) {
                if (event.target == modal) {
                    videoModal.close();
                }
            }
            
            utils.log('Legacy modal support initialized');
        }
    };

    // ================================================================
    // MAIN INITIALIZATION FUNCTION
    // ================================================================
    function init() {
        const deviceType = utils.isMobile() ? 'Mobile' : utils.isTablet() ? 'Tablet' : 'Desktop';
        utils.log(`Initializing for ${deviceType} device (${window.innerWidth}x${window.innerHeight})`);
        
        // Cache DOM elements first
        initElements();

        // Initialize core components (all devices)
        loader.hide();
        videoModal.init();
        backToTop.init();
        smoothScroll.init();
        scrollAnimations.init();
        resizeHandler.init();
        visibilityHandler.init();
        performance.init();
        errorHandler.init();
        legacyModal.init();

        // Initialize mobile-specific features
        utils.log('Initializing mobile menu for all screen sizes');
        mobileMenu.init(); // Always initialize mobile menu
        
        if (utils.isMobile()) {
            utils.log('Initializing additional mobile-specific features');
            mobileNavAutoHide.init();
            mobileTouch.init();
        }

        // Set initial back to top visibility
        backToTop.toggleVisibility();
        
        utils.log('Initialization complete');
    }

    // ================================================================
    // DEVICE-SPECIFIC FEATURE TOGGLES
    // ================================================================
    function updateDeviceFeatures() {
        if (utils.isMobile()) {
            // Enable mobile features
            if (!mobileMenu.isInitialized) {
                mobileMenu.init();
                mobileNavAutoHide.init();
                mobileTouch.init();
            }
        } else {
            // Disable mobile features on larger screens
            if (mobileMenu.isOpen) {
                mobileMenu.close();
            }
        }
    }

    // ================================================================
    // START APPLICATION
    // ================================================================
    
    // Initialize when DOM is ready
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

    // Handle dynamic device changes
    window.addEventListener('resize', utils.debounce(updateDeviceFeatures, 250));

    // ================================================================
    // GLOBAL API (EXPOSE FUNCTIONS FOR EXTERNAL USE)
    // ================================================================
    window.ClairDunneWebsite = {
        // Core modules
        mobileMenu: mobileMenu,
        videoModal: videoModal,
        backToTop: backToTop,
        
        // Utility functions
        utils: {
            isMobile: utils.isMobile,
            isTablet: utils.isTablet,
            isDesktop: utils.isDesktop,
            getScrollPosition: utils.getScrollPosition
        },
        
        // Manual initialization for specific components
        init: {
            mobileMenu: () => mobileMenu.init(),
            videoModal: () => videoModal.init(),
            backToTop: () => backToTop.init(),
            scrollAnimations: () => scrollAnimations.init()
        },
        
        // Device information
        device: {
            get type() {
                return utils.isMobile() ? 'mobile' : utils.isTablet() ? 'tablet' : 'desktop';
            },
            get width() {
                return window.innerWidth;
            },
            get height() {
                return window.innerHeight;
            }
        }
    };

})();

// ================================================================
// ADDITIONAL ENHANCEMENTS FOR MODERN BROWSERS
// ================================================================

document.addEventListener('DOMContentLoaded', function() {
    
    // ================================================================
    // ENHANCED INTERSECTION OBSERVER FOR IMAGES (ALL DEVICES)
    // ================================================================
    if ('IntersectionObserver' in window) {
        const imageObserver = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    const image = entry.target;
                    image.classList.add('loaded');
                    
                    // Add fade-in effect
                    image.style.opacity = '1';
                    image.style.transform = 'scale(1)';
                    
                    imageObserver.unobserve(image);
                }
            });
        }, { 
            threshold: 0.1,
            rootMargin: '50px'
        });
        
        // Observe all section images
        const images = document.querySelectorAll('.section-half .image');
        images.forEach(image => {
            image.style.opacity = '0.8';
            image.style.transform = 'scale(1.02)';
            image.style.transition = 'all 0.6s ease';
            imageObserver.observe(image);
        });
    }
    
    // ================================================================
    // PRELOAD CRITICAL RESOURCES (ALL DEVICES)
    // ================================================================
    function preloadResources() {
        // Preload video thumbnail or poster if available
        const videoBtn = document.getElementById('myBtn');
        if (videoBtn) {
            // Preload video thumbnail
            const link = document.createElement('link');
            link.rel = 'prefetch';
            link.href = 'https://img.youtube.com/vi/EDkTA3oewCs/maxresdefault.jpg';
            document.head.appendChild(link);
        }
    }
    
    // ================================================================
    // ACCESSIBILITY ENHANCEMENTS (ALL DEVICES)
    // ================================================================
    function enhanceAccessibility() {
        // Add proper ARIA labels
        const burgerMenu = document.querySelector('.probootstrap-burger-menu');
        if (burgerMenu) {
            burgerMenu.setAttribute('aria-label', 'Toggle navigation menu');
            burgerMenu.setAttribute('aria-expanded', 'false');
        }
        
        const modalClose = document.querySelector('.modal-close');
        if (modalClose) {
            modalClose.setAttribute('aria-label', 'Close video modal');
        }
        
        // Add focus management for modal
        const modal = document.getElementById('myModal');
        if (modal) {
            modal.addEventListener('keydown', function(e) {
                // Trap focus within modal when open
                if (e.key === 'Tab' && modal.classList.contains('show')) {
                    const focusableElements = modal.querySelectorAll('button, iframe, [tabindex]:not([tabindex="-1"])');
                    const firstElement = focusableElements[0];
                    const lastElement = focusableElements[focusableElements.length - 1];
                    
                    if (e.shiftKey) {
                        if (document.activeElement === firstElement) {
                            lastElement.focus();
                            e.preventDefault();
                        }
                    } else {
                        if (document.activeElement === lastElement) {
                            firstElement.focus();
                            e.preventDefault();
                        }
                    }
                }
            });
        }
    }
    
    // ================================================================
    // SERVICE WORKER REGISTRATION (PROGRESSIVE WEB APP)
    // ================================================================
    function registerServiceWorker() {
        if ('serviceWorker' in navigator) {
            navigator.serviceWorker.register('/sw.js')
                .then(registration => {
                    console.log('Service Worker registered successfully');
                })
                .catch(error => {
                    console.log('Service Worker registration failed');
                });
        }
    }
    
    // ================================================================
    // INITIALIZE ENHANCEMENTS
    // ================================================================
    preloadResources();
    enhanceAccessibility();
    
    // Register service worker only in production
    if (location.protocol === 'https:' && location.hostname !== 'localhost') {
        registerServiceWorker();
    }
    
    // Final device-specific log
    const deviceInfo = window.ClairDunneWebsite ? window.ClairDunneWebsite.device : null;
    if (deviceInfo) {
        console.log(`✅ Clair Dunne Website initialized for ${deviceInfo.type} (${deviceInfo.width}x${deviceInfo.height})`);
    }
});